args.command:
cd /home/runner/work/yyds-harness/yyds-harness && python3 -c "
import json, collections
types = collections.Counter()
with open('.yoyo/state/events.jsonl') as f:
    for line in f:
        try:
            evt = json.loads(line)
            types[evt.get('event_type', '?')] += 1
        except:
            types['parse_error'] += 1
for t, c in types.most_common():
    print(f'{c:5d}  {t}')
"

